products.model:
'use strict';

function normalizeField(value, fieldName) {
  if (typeof value !== 'string') {
    throw new TypeError(`${fieldName} must be a string`);
  }
  const trimmed = value.trim();
  if (trimmed.length === 0) {
    throw new TypeError(`${fieldName} must not be empty`);
  }
  return trimmed;
}

function normalizeBook(input) {
  if (input === null || typeof input !== 'object') {
    throw new TypeError('book input must be an object');
  }
  const title = normalizeField(input.title, 'title');
  const author = normalizeField(input.author, 'author');
  return { title, author };
}

module.exports = { normalizeBook };

products.api:
'use strict';

const { normalizeBook } = require('./model.cjs');

function handleCreateBook(request) {
  try {
    const book = normalizeBook(request.body);
    return { status: 201, body: { book } };
  } catch (err) {
    if (err instanceof TypeError) {
      return { status: 400, body: { error: err.message } };
    }
    throw err;
  }
}

module.exports = { handleCreateBook };

